#include <bits/stdc++.h>
using namespace std;
const int mod=1e9+7;
int n,m,k,dp[2][202][202],g[2][202][202];
string a,b;
int main(){
	scanf("%d%d%d",&n,&m,&k);
	cin>>a>>b;
	a=" "+a,b=" "+b;
	for(int i=0;i<2;i++)
		dp[i][0][0]=1;
	for(int i=1;i<=n;i++)
		for(int j=1;j<=m;j++)
			for(int l=1;l<=k;l++){
				g[i&1][j][l]=0;
				if(a[i]==b[j])
					g[i&1][j][l]=g[(i&1)^1][j-1][l]+dp[(i&1)^1][j-1][l-1],g[i&1][j][l]%=mod;
				dp[i&1][j][l]=dp[(i&1)^1][j][l];
				if(a[i]==b[j])
					dp[i&1][j][l]+=g[i&1][j][l];
				dp[i&1][j][l]%=mod;
				/*for(int t=1;t<=min(i,j) && a[i-t+1]==b[j-t+1];t++)
					dp[i][j][l]+=dp[i-t][j-t][l-1];*/
			}
	printf("%d",dp[n&1][m][k]);
	return 0;
}
